mapper.sql:
WITH T_MSG AS ( SELECT A.MULAAPMSGHDKEY , B.MSGTYPE , B.DISPLAYMSG FROM TADMIN_MST_MULAAPMSG_HD A INNER JOIN TADMIN_MST_MULAAPMSG_DT B ON B.MULAAPMSGHDKEY = A.MULAAPMSGHDKEY
AND LAKEY = #{lakey}
AND A.CLOSDATE >= TO_CHAR(CURRENT_TIMESTAMP, 'YYYYMMDDHH24MISS')
)

mapper.insert:
/* adm-menu-searchcondition-sql-oracle.xml - insertSearchCondition */
INSERT INTO TADMIN_MST_USSC_HD (
	  USSCHDKEY
	, USSCHDNM
	, INSERTDATE
	, INSERTURKEY
	, UPDATEDATE
	, UPDATEURKEY
	, CLOSDATE
) VALUES (
	  #{usschdkey}
	, #{usschdnm}
	, #{sysdate}
	, #{surkey}
	, #{sysdate}
	, #{surkey}
	, #{closdate}
)

mapper.update:
/* adm-menu-searchcondition-sql-oracle.xml - updateSearchCondition */
UPDATE
    TADMIN_MST_USSC_HD
SET
      USSCHDNM = #{usschdnm}
	, UPDATEDATE = #{sysdate}
  	, UPDATEURKEY = #{surkey}
WHERE
    USSCHDKEY = #{usschdkey}

mapper.delete:
/* adm-menu-searchcondition-sql-oracle.xml - deleteSearchCondition */
DELETE
FROM
    TADMIN_MST_USSC_HD
WHERE
    USSCHDKEY = #{usschdkey}

mapper.select:
/* adm-menu-searchcondition-sql-oracle.xml - selectSearchConditionDetailList */
SELECT '0' AS CHK , A.USSCHDKEY , A.USSCDTKEY , A.USSCORDER , A.USSCDTTYPE , A.USSCLABEL , B.DISPLAYMSG AS USSC_LABEL_LANG , A.DBFIELDNM , A.SEARCHID , A.DEFAULTOPERATOR , A.DEFAULTVALUE , A.ISMANDATORY , A.GMTAPPLYCHK , A.DATEFORMAT AS YMDFORMAT , A.FRDATEVALUE , A.TODATEVALUE , A.INSERTDATE , A.INSERTURKEY AS INSERTURNAME , A.UPDATEDATE , A.UPDATEURKEY AS UPDATEURNAME FROM TADMIN_MST_USSC_DT A LEFT OUTER JOIN T_MSG B ON B.MULAAPMSGHDKEY = A.USSCLABEL AND B.MSGTYPE = 'TEXT'
AND USSCHDKEY = #{usschdkey}
AND USSCDTKEY = #{usscdtkey}
ORDER BY USSCORDER ASC

