	, GMTAPPLYCHK
	, DATEFORMAT
	, FRDATEVALUE
	, TODATEVALUE
	, ISMANDATORY
	, INSERTDATE
	, INSERTURKEY
	, UPDATEDATE
	, UPDATEURKEY
) VALUES (
	  #{usschdkey}
	, #{usscdtkey}
	, #{usscorder}
	, #{usscdttype}
	, #{ussclabel}
	, #{dbfieldnm}
	, #{searchid}
	, #{defaultoperator}
	, #{defaultvalue}
	, #{gmtapplychk}
	, #{ymdformat}
	, #{frdatevalue}
	, #{todatevalue}
	, #{ismandatory}
	, #{sysdate}
	, #{surkey}
	, #{sysdate}
	, #{surkey}
)

mapper.update:
/* adm-menu-searchcondition-sql-oracle.xml - updateSearchConditionDetail */
UPDATE
    TADMIN_MST_USSC_DT
SET
	  USSCORDER = #{usscorder}
	, USSCDTTYPE = #{usscdttype}
	, USSCLABEL = #{ussclabel}
	, DBFIELDNM = #{dbfieldnm}
	, SEARCHID = #{searchid}
	, DEFAULTOPERATOR = #{defaultoperator}
	, DEFAULTVALUE = #{defaultvalue}
	, GMTAPPLYCHK = #{gmtapplychk}
	, DATEFORMAT = #{ymdformat}
	, FRDATEVALUE = #{frdatevalue}
	, TODATEVALUE = #{todatevalue}
	, ISMANDATORY = #{ismandatory}
	, UPDATEDATE = #{sysdate}
	, UPDATEURKEY = #{surkey}
WHERE USSCHDKEY = #{usschdkey}
AND USSCDTKEY = #{usscdtkey}

